import { beforeEach, describe, expect, it, vi } from 'vitest';
globalThis.window={secureElectronAPI:{analytics:{trackEvent:vi.fn()}},debugLog:{info:vi.fn(),warn:vi.fn(),error:vi.fn(),debug:vi.fn()},matchMedia:vi.fn(()=>({matches:true,addEventListener:vi.fn()}))};
const bodyClasses=new Set(); globalThis.CustomEvent=class CustomEvent{constructor(name,options){this.type=name;this.detail=options.detail;}}; globalThis.document={body:{className:'',classList:{add:x=>bodyClasses.add(x),remove:(...xs)=>xs.forEach(x=>bodyClasses.delete(x))}},documentElement:{style:{setProperty:vi.fn()}},dispatchEvent:vi.fn(),getElementById:vi.fn(()=>null),querySelectorAll:vi.fn(()=>[]),querySelector:vi.fn(()=>null)};
const bootstrap=await import('../../../src/renderer/modules/app-bootstrap/index.js'); const theme=(await import('../../../src/renderer/modules/theme-management/index.js')).default; const EventDelegator=(await import('../../../src/renderer/modules/event-coordination/event-delegator.js')).default;
describe('bootstrap and theme contracts',()=>{beforeEach(()=>vi.clearAllMocks());
it('rejects theme initialization without required modules',async()=>{await expect(bootstrap.initializeThemeManagement({},vi.fn(),vi.fn())).resolves.toBe(false);});
it('initializes and applies system/user theme to DOM state',async()=>{await expect(theme.initThemeManagement({preferencesModule:{getScreenMode:vi.fn(async()=> 'auto')}})).resolves.toMatchObject({success:true,theme:'dark'});expect(bodyClasses.has('theme-dark')).toBe(true);expect(document.documentElement.style.setProperty).toHaveBeenCalledWith('--current-theme','dark');});});
describe('event delegation lifecycle',()=>{it('registers delegated handlers once and cleans them up',async()=>{const handlers={};const table={addEventListener:(n,h)=>{handlers[n]=h;},removeEventListener:vi.fn(),contains:()=>true};document.getElementById.mockReturnValue(table);const toggleSelectedRow=vi.fn();const delegator=new EventDelegator({moduleRegistry:{ui:{toggleSelectedRow}},debugLog:window.debugLog});await delegator.setupEventDelegation();await delegator.setupEventDelegation();expect(delegator.getStatus()).toMatchObject({isSetup:true,handlerCount:3});const row={};handlers.click({target:{closest:()=>row}});expect(toggleSelectedRow).toHaveBeenCalledWith(row);delegator.cleanup();expect(delegator.getStatus().handlerCount).toBe(0);expect(table.removeEventListener).toHaveBeenCalledTimes(3);});});
